import concurrent.futures

def worker(arg):
    # 执行实际任务
    return arg * 2

with concurrent.futures.ThreadPoolExecutor(max_workers=4) as executor:
    args = [1, 2, 3, 4]
    future_to_arg = {executor.submit(worker, arg): arg for arg in args}
    for future in concurrent.futures.as_completed(future_to_arg):
        try:
            result = future.result()
            arg = future_to_arg[future]
            print(f"Task {arg} completed with result: {result}")
        except Exception as e:
            print(f"Task raised exception: {e}")
